#!/bin/bash\n# PandaStack Deployment Helper Script for koshi\n# Usage: ./scripts/pandastack-deploy.sh [command]\n# Commands: health, test, deploy, logs, rollback, status\n\nset -e\n\n# Configuration\nPROJECT_NAME=\"koshi\"\nPROJECT_URL=\"https://koshi.pandastack.app\"\nAPI_HEALTH=\"$PROJECT_URL/health\"\nDASHBOARD=\"https://dashboard.pandastack.io\"\n\n# Colors for output\nRED='\\033[0;31m'\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nBLUE='\\033[0;34m'\nNC='\\033[0m' # No Color\n\n# Functions\nprint_header() {\n    echo -e \"\\n${BLUE}=== $1 ===${NC}\\n\"\n}\n\nprint_success() {\n    echo -e \"${GREEN}✓ $1${NC}\"\n}\n\nprint_error() {\n    echo -e \"${RED}✗ $1${NC}\"\n    exit 1\n}\n\nprint_warning() {\n    echo -e \"${YELLOW}! $1${NC}\"\n}\n\n# Check health\ncheck_health() {\n    print_header \"Health Check\"\n    \n    if curl -s \"$API_HEALTH\" | grep -q \"ok\"; then\n        print_success \"API is healthy\"\n        curl -s \"$API_HEALTH\" | jq .\n        return 0\n    else\n        print_error \"API is not responding\"\n    fi\n}\n\n# Run local tests\nrun_tests() {\n    print_header \"Running Tests\"\n    \n    if [ -f \"package.json\" ]; then\n        npm test || print_error \"Tests failed\"\n        print_success \"All tests passed\"\n    else\n        print_warning \"No package.json found\"\n    fi\n}\n\n# Deploy to PandaStack\ndeploy() {\n    print_header \"Deploying to PandaStack\"\n    \n    # Check if pandastack CLI is installed\n    if ! command -v pandastack &> /dev/null; then\n        print_warning \"PandaStack CLI not found. Installing...\"\n        npm install -g @pandastack/cli\n    fi\n    \n    # Run tests before deploy\n    print_header \"Pre-deployment Checks\"\n    npm test || print_error \"Pre-deployment tests failed\"\n    \n    # Deploy\n    print_header \"Pushing to GitHub (triggers auto-deploy)\"\n    echo \"Committing changes...\"\n    git add -A\n    git commit -m \"chore: auto-deploy $(date +%Y-%m-%d_%H:%M:%S)\" || echo \"No changes to commit\"\n    \n    echo \"Pushing to main branch...\"\n    git push origin main\n    \n    print_success \"Pushed to GitHub. PandaStack will auto-deploy.\"\n    print_warning \"Watch deployment progress at: $DASHBOARD\"\n    \n    # Wait and check health\n    echo -e \"\\nWaiting 10 seconds for deployment...\"\n    sleep 10\n    \n    echo \"Checking health...\"\n    check_health || print_error \"Deployment may have failed\"\n}\n\n# Show logs\nshow_logs() {\n    print_header \"Application Logs\"\n    \n    if command -v pandastack &> /dev/null; then\n        pandastack logs $PROJECT_NAME --follow\n    else\n        print_warning \"PandaStack CLI not found\"\n        echo \"View logs at: $DASHBOARD\"\n    fi\n}\n\n# Show status\nshow_status() {\n    print_header \"Deployment Status\"\n    \n    echo \"Project: $PROJECT_NAME\"\n    echo \"Dashboard: $DASHBOARD\"\n    echo \"Live URL: $PROJECT_URL\"\n    \n    echo -e \"\\nHealth Check:\"\n    if curl -s \"$API_HEALTH\" > /dev/null 2>&1; then\n        print_success \"Online\"\n        curl -s \"$API_HEALTH\" | jq .\n    else\n        print_error \"Offline\"\n    fi\n}\n\n# Rollback to previous deployment\nrollback() {\n    print_header \"Rollback Instructions\"\n    \n    echo \"To rollback:\"\n    echo \"1. Go to $DASHBOARD\"\n    echo \"2. Click on project '$PROJECT_NAME'\"\n    echo \"3. Go to 'Deployments' tab\"\n    echo \"4. Click on previous working deployment\"\n    echo \"5. Click 'Rollback' button\"\n    echo \"\"\n    print_warning \"Or use: git revert <commit-sha> && git push origin main\"\n}\n\n# Show help\nshow_help() {\n    cat <<EOF\n${BLUE}PandaStack Deployment Helper for koshi${NC}\n\nUsage: $0 [command]\n\nCommands:\n  health    - Check API health\n  test      - Run local tests\n  deploy    - Run tests and push to GitHub (triggers auto-deploy)\n  logs      - Show live application logs\n  status    - Show deployment status\n  rollback  - Show rollback instructions\n  help      - Show this help message\n\nExamples:\n  $0 health        # Check if API is running\n  $0 test          # Run npm test\n  $0 deploy        # Deploy to production\n  $0 logs          # Watch live logs\n  $0 status        # Show deployment info\n\nEnvironment Variables:\n  PROJECT_NAME    - PandaStack project name (default: koshi)\n  PROJECT_URL     - Production URL (default: https://koshi.pandastack.app)\n  DASHBOARD       - Dashboard URL (default: https://dashboard.pandastack.io)\n\nFor more info, see: $DASHBOARD\nEOF\n}\n\n# Main\ncase \"${1:-help}\" in\n    health)\n        check_health\n        ;;\n    test)\n        run_tests\n        ;;\n    deploy)\n        deploy\n        ;;\n    logs)\n        show_logs\n        ;;\n    status)\n        show_status\n        ;;\n    rollback)\n        rollback\n        ;;\n    help|--help|-h)\n        show_help\n        ;;\n    *)\n        print_error \"Unknown command: $1\"\n        ;;\nesac\n"